INSERT INTO `wp_options` VALUES (224,'frm_addons_l','a:3:{s:7:\"timeout\";i:1774697690;s:5:\"value\";s:116764:\"{\"93790\":{\"title\":\"Formidable Pro\",\"name\":\"Formidable Pro\",\"display_name\":\"Formidable Pro\",\"slug\":\"formidable-pro\",\"version\":\"6.29\",\"new_version\":\"6.29\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-pro-6.29.zip\"],\"excerpt\":\"\",\"id\":93790,\"released\":\"2010-02-01 16:27:26\",\"categories\":[\"Basic\",\"Strategy11\"],\"docs\":\"\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/formidable-pro\\/\",\"changelog\":\"<h4>v6.29 - March 11, 2026<\\/h4>\\n<ul>\\n<li>New: A new Virtual field type has been added. This new field type is never included in front end HTML, and its values cannot be manipulated. This field type is ideal for fields that handle meta and sensitive data.<\\/li>\\n<li>Fix: The text area for setting calculations is now scrollable for fields with long calculation strings.<\\/li>\\n<li>Fix: A JS error would occur when trying to delete a field option with double quote characters that are used in conditional logic.<\\/li>\\n<li>Fix: Currency formatted values would not properly work when used as Slider field values.<\\/li>\\n<li>Fix: New protected file checks have been added to help prevent an infinite recursion conflict issue with Elementor.<\\/li>\\n<\\/ul>\\n<h4>v6.28 - February 12, 2026<\\/h4>\\n<ul>\\n<li>New: New \\\"Set option limits\\\" and \\\"Show remaining quantity\\\" settings have been added to fields with options (Radio buttons, Dropdowns, and Checkboxes). When \\\"Set option limits\\\" is active, additional \\\"Limit\\\" settings are included for each option.<\\/li>\\n<li>Fix: Date fields labels would incorrectly overlap the value when using the setting to include the label as a placeholder inside of the field.<\\/li>\\n<li>Fix: The selected date styling has been updated on admin pages using flatpickr to fix an issue where the selected date would not be visible because it was displaying white on white.<\\/li>\\n<li>Fix: The reports filter would not work on some sites where other forms were embedded in the admin bar.<\\/li>\\n<li>Fix: The title and description settings would not properly carry over when clicking the start over button.<\\/li>\\n<li>Fix: The pop-up to edit an application would not properly open after Bootstrap version changes in Formidable Lite.<\\/li>\\n<li>Fix: File uploads would result in fatal errors on sites where the mime_content_type function does not exist.<\\/li>\\n<li>Fix: Currency formatted fields would appear as blank on page load until the field gained focus in some cases.<\\/li>\\n<li>Breaking: The deprecated functions FrmProStylesController::style_dropdown, FrmProStylesController::add_new_button, and FrmProStylesController::get_disabled_javascript_features have been removed.<\\/li>\\n<li>Breaking: The deprecated frm_graph_values, frm_graph_labels, and frm_final_graph_values hooks have all been removed.<\\/li>\\n<\\/ul>\\n<h4>v6.27 - January 13, 2026<\\/h4>\\n<ul>\\n<li>New: An additional check has been added before generating thumbnails for uploaded PDF files, to prevent file upload errors when ImageMagick seg faults when trying to read some PDFs.<\\/li>\\n<li>New: The number spinner is no longer shown in Safari for a readonly number field.<\\/li>\\n<li>Fix: When trying to upload some files using Chrome on Android, a \\\"Server responded with 0 code\\\" error response would get returned.<\\/li>\\n<li>Fix: When clicking on an international phone field input on a long page, it would trigger a scroll event, preventing the dropdown options from appearing after recent updates to the international phone input library.<\\/li>\\n<li>Fix: &#091;age] shortcodes would not properly work in flatpickr fields when using a date format that uses dots instead of dashes.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-pro\\/formidable-pro.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-772x250.png\"},\"search_terms\":\"\",\"is_new\":false},\"163248\":{\"title\":\"Signature\",\"name\":\"Signature\",\"display_name\":\"Digital Signatures\",\"slug\":\"signature\",\"version\":\"3.0.6\",\"new_version\":\"3.0.6\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-signature\\/formidable-signature-3.0.6.zip\"],\"excerpt\":\"Add an electronic signature to your WordPress form. The visitor may write their signature with a trackpad\\/mouse or type it.\",\"id\":163248,\"released\":\"2013-03-04 00:00:00\",\"categories\":[\"Business\",\"Form Functionality\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-signature\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/signature\\/\",\"changelog\":\"<h4>v3.0.6 - September 9, 2025<\\/h4>\\n<ul>\\n<li>Fix: Translations are now loaded on the init hook to improve compatibility with WordPress 6.7+.<\\/li>\\n<li>Signature field settings have been updated to match field settings updates introduced in Formidable Forms v6.24.<\\/li>\\n<\\/ul>\\n<h4>v3.0.5 - August 19, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<li>Fix: A Use of \\\"parent\\\" in callables deprecated message would get logged when loading translations for signature fields.<\\/li>\\n<li>Fix: In some cases old cached signature images would appear after being updated.<\\/li>\\n<li>Old polyfill code for supporting Internet Explorer has been removed.<\\/li>\\n<\\/ul>\\n<h4>v3.0.4 - March 28, 2024<\\/h4>\\n<ul>\\n<li>New: The way CSS is added has been updated for better compatibility with the Snuffleupagus security module.<\\/li>\\n<li>Fix: Scripts were not properly initializing when editing a form with a signature field in-place using the &#091;editlink] shortcode.<\\/li>\\n<li>Fix: Form validation would trigger on signature draw events, causing error messages to appear on other fields early.<\\/li>\\n<li>Fix: An Uncaught Error: Call to undefined method FrmProFieldDefault::get_signature_image_dimension fatal error has been fixed.<\\/li>\\n<li>Front end signature field icons have been updated to no longer use font icons.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-signature\\/signature.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"163255\":{\"title\":\"Math Captcha\",\"name\":\"Math Captcha\",\"display_name\":\"Math Captcha\",\"slug\":\"math-captcha\",\"version\":\"1.15\",\"new_version\":\"1.15\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-math-captcha\\/formidable-math-captcha-1.15.zip\"],\"excerpt\":\"\",\"id\":163255,\"released\":\"2015-10-12 14:00:35\",\"categories\":[],\"docs\":\"\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/math-captcha\\/\",\"changelog\":\"\",\"plugin\":\"math-captcha\\/math-captcha.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"163257\":{\"title\":\"PayPal Standard\",\"name\":\"PayPal Standard\",\"display_name\":\"PayPal Standard\",\"slug\":\"paypal-standard\",\"version\":\"3.09\",\"new_version\":\"3.09\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-paypal\\/formidable-paypal-3.09.zip\"],\"excerpt\":\"Collect instant payments and recurring payments to automate your online business. Calculate a total and send customers on to PayPal.\",\"id\":163257,\"released\":\"2012-09-04 00:00:00\",\"categories\":[\"Business\",\"Ecommerce\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-paypal\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/paypal-standard\\/\",\"changelog\":\"<h4>v3.10 - December 31, 2024<\\/h4>\\n<ul>\\n<li>Fix: An Undefined array key \\\"expire_date\\\" PHP Warning has been fixed.<\\/li>\\n<li>Fix: An Uncaught TypeError: strtotime PHP Fatal error has been fixed.<\\/li>\\n<\\/ul>\\n<h4>v3.09 - July 30, 2019<\\/h4>\\n<ul>\\n<li>New: Account for tax when comparing amounts with the IPN<\\/li>\\n<li>Update form action icon and color<\\/li>\\n<li>Replace call to deprecated function with FrmFieldsHelper::get_user_display_name<\\/li>\\n<li>Requires Formidable v3.0+<\\/li>\\n<\\/ul>\\n<h4>v3.08 - November 18, 2017<\\/h4>\\n<ul>\\n<li>Allow field shortcodes in more payments settings so values can be set from the form: PayPal email, trial amount, repeat period, trial length. This also allows payments to go to other members on your site.<\\/li>\\n<li>Allow regular WordPress shortcodes and Formidable dynamic values (ie [email]) in addition to basic field shortcodes<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-paypal\\/formidable-paypal.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"paypal\",\"is_new\":false},\"168072\":{\"title\":\"Formidable API\",\"name\":\"Formidable API\",\"display_name\":\"Formidable API\",\"slug\":\"formidable-api\",\"version\":\"1.18\",\"new_version\":\"1.18\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-api\\/formidable-api-1.18.zip\"],\"excerpt\":\"Add a full forms API for forms, form fields, views, and entries. Then send submissions to other sites with REST APIs.\",\"id\":168072,\"released\":\"2016-06-08 00:00:00\",\"categories\":[\"Automation\",\"Business\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-api\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/formidable-api\\/\",\"changelog\":\"<h4>v1.18 - December 11, 2024<\\/h4>\\n<ul>\\n<li>New: Testing API connections has been improved. Previously messages like OK would appear in red even though the connection was valid.<\\/li>\\n<li>Fix: Icons to add or remove data rows in API actions were missing after a recent v6.16.3 Formidable Forms update.<\\/li>\\n<li>Fix: The hook used to load translations has been updated to improve compatibility with WordPress 6.7+.<\\/li>\\n<li>Fix: Files would not properly save when creating entries using the rest API when file protection was enabled.<\\/li>\\n<\\/ul>\\n<h4>v1.17 - October 15, 2024<\\/h4>\\n<ul>\\n<li>New: API keys can now be refreshed. This will disallow all uses of your previous API key, allowing you to pick another in case your API key may have been compromised.<\\/li>\\n<li>Fix: Using API actions to send GET requests could result in a fatal error.<\\/li>\\n<li>Fix: Trying to use an &#091;frm-api] shortcode without Formidable Forms active would result in a fatal error.<\\/li>\\n<li>Fix: Trying to update an entry with a required name field in a repeater would result in an unexpected 409 error.<\\/li>\\n<li><span class=\\\"blob-code-inner blob-code-marker js-code-nav-pass \\\" data-code-marker=\\\"+\\\"><span class=\\\"pl-s\\\">The entry object is now passed as a parameter when the frm_before_destroy_entry hook is triggered to match parameters in other locations where the hook is triggered.<br \\/>\\n<\\/span><\\/span><\\/li>\\n<\\/ul>\\n<h4>v1.16 - August 21, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<li>New: A new frm_api_allow_create_entry filter has been added to override errors permission errors when creating an entry using the REST API.<\\/li>\\n<li>New: The frm_api_request_args filter is now applied when testing a connection to make testing a connection more consistent with real requests that get sent.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-api\\/formidable-api.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"168456\":{\"title\":\"Upload Importer\",\"name\":\"Upload Importer\",\"display_name\":\"Upload Importer\",\"slug\":\"upload-importer\",\"version\":\"1.0.01\",\"new_version\":\"1.0.01\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-upload-importer\\/formidable-upload-importer-1.0.01.zip\"],\"excerpt\":\"\",\"id\":168456,\"released\":\"2015-10-16 17:05:47\",\"categories\":[\"Strategy11\"],\"docs\":\"\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/upload-importer\\/\",\"changelog\":\"<h4>v1.0.01<\\/h4>\\n<ul>\\n<li>Get updates from FormidablePro.com<\\/li>\\n<\\/ul>\\n<h4>v1.0<\\/h4>\\n<ul>\\n<li>Allow importing of multiple file uploads<\\/li>\\n<li>Replace deprecated mime_content_type with fileinfo<\\/li>\\n<li>Update auto-updating<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"upload-importer\\/upload-importer.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"168460\":{\"title\":\"Twilio\",\"name\":\"Twilio\",\"display_name\":\"Twilio WordPress SMS\",\"slug\":\"twilio\",\"version\":\"1.09\",\"new_version\":\"1.09\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-twilio\\/formidable-twilio-1.09.zip\"],\"excerpt\":\"Allow users to text their votes for polls created by Formidable Forms, or send SMS notifications when entries are submitted or updated.\",\"id\":168460,\"released\":\"2014-03-10 00:00:00\",\"categories\":[\"Business\",\"Email &amp; SMS Marketing\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/twilio-add-on\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/twilio\\/\",\"changelog\":\"<h4>v1.10 - August 26, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<li>New: Twilio requests are now logged using the logging add-on when the plugin is available.<\\/li>\\n<li>New: Twilio actions now include the option to trigger on import.<\\/li>\\n<\\/ul>\\n<h4>v1.09 - November 2, 2020<\\/h4>\\n<ul>\\n<li>New: Include sending numbers from the linked Twilio account in a dropdown. This makes it much easier to send messages successfully.<\\/li>\\n<li>New: Process the [default-message] when sending in an SMS message.<\\/li>\\n<li>Add more guidance to connect to the Twilio API and show messages in the form action when connecting fails.<\\/li>\\n<li>Fix: Some responses were not getting saved correctly into radio and checkbox fields.<\\/li>\\n<li>Clean up and update the code including removing support for Formidable &lt;2.0.<\\/li>\\n<\\/ul>\\n<h4>v1.08 - January 16, 2017<\\/h4>\\n<ul>\\n<li>Improved: Removed deprecated instructions and screenshot.<\\/li>\\n<li>Improved: Removed deprecated valign attribute from table HTML.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-twilio\\/formidable-twilio.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"168463\":{\"title\":\"Bootstrap\",\"name\":\"Bootstrap\",\"display_name\":\"Bootstrap\",\"slug\":\"bootstrap\",\"version\":\"2.0.1\",\"new_version\":\"2.0.1\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-bootstrap\\/formidable-bootstrap-2.0.1.zip\"],\"excerpt\":\"Instantly add Bootstrap styling to all your Formidable forms.\",\"id\":168463,\"released\":\"2014-08-05 00:00:00\",\"categories\":[\"Creator\",\"Form Design &amp; Display\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-bootstrap\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/bootstrap\\/\",\"changelog\":\"<h4>v2.0.1 - August 13, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<\\/ul>\\n<h4>v2.0 - November 30, 2023<\\/h4>\\n<ul>\\n<li>New: This add on now uses Bootstrap 5 (instead of Bootstrap 3). If moving to Bootstrap 5 is causing issues, the option to change back to Bootstrap 3 is available as a dropdown option in Global Settings.<\\/li>\\n<li>New: Admin page labels for Bootstrap settings have been updated for better accessibility.<\\/li>\\n<li>Fix: Radio button options displayed as buttons had too much left padding when using Bootstrap 3.<\\/li>\\n<li>Fix: Too many migration queries were being made when there was no Bootstrap data to migrate.<\\/li>\\n<li>Fix: The ellipses used in pagination containers was appearing as text outside of the pagination when using the Bootstrap add on.<\\/li>\\n<\\/ul>\\n<h4>vv1.03 - January 18, 2021<\\/h4>\\n<ul>\\n<li>This update requires action. After updating, click the link to migrate the old settings.<strong> If you save a form with Bootstrap field options before running this migration, you risk losing those settings.<\\/strong><\\/li>\\n<li>New: Moved Prepend and Append Bootstrap field options to Before Input and After Input.<\\/li>\\n<li>New: Errors are now shown by default and can no longer be turned off<\\/li>\\n<li>New: Improved plugin security<\\/li>\\n<li>New: Added bootstrap CSS file directly into plugin for GDPR compliance<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-bootstrap\\/formidable-bootstrap.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"168468\":{\"title\":\"AWeber\",\"name\":\"AWeber\",\"display_name\":\"AWeber\",\"slug\":\"aweber\",\"version\":\"2.05\",\"new_version\":\"2.05\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-aweber\\/formidable-aweber-2.05.zip\"],\"excerpt\":\"AWeber is a powerful email marketing service. Subscribe contacts to an AWeber mailing list when they submit your WordPress contact forms.\",\"id\":168468,\"released\":\"2013-11-26 00:00:00\",\"categories\":[\"Creator\",\"Email &amp; SMS Marketing\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-aweber\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/aweber\\/\",\"changelog\":\"<h4>v2.05 - August 20, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<li>Fix: Undefined array key \\\"ad_tracking\\\" and Undefined array key \\\"tags\\\" PHP warnings have been fixed when adding a new AWeber action.<\\/li>\\n<li>The deprecated <span class=\\\"blob-code-inner blob-code-marker js-code-nav-pass js-skip-tagsearch\\\" data-code-marker=\\\"-\\\"><span class=\\\"pl-en x x-first\\\">utf8_encode<\\/span><\\/span> PHP function is no longer referenced.<\\/li>\\n<\\/ul>\\n<h4>v2.04 - June 11, 2024<\\/h4>\\n<ul>\\n<li>New: Field dropdowns have been updated to enable support for repeater actions.<\\/li>\\n<li>Fix: Name fields will now properly concatenate the first and last name when sending data to AWeber.<\\/li>\\n<li>Fix: An Uncaught TypeError: preg_match(): Argument 2 must be of type string fatal error has been fixed when trying to remove accents from array data.<\\/li>\\n<\\/ul>\\n<h4>v2.03 - March 3, 2022<\\/h4>\\n<ul>\\n<li>New: Subscription errors and successful subscriptions will now be logged if the Formidable Logs add on is available.<\\/li>\\n<li>Fix: Accents will now be removed from characters when subscribing to avoid issues with special accented characters breaking in names in AWeber.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-aweber\\/formidable-aweber.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"169998\":{\"title\":\"WP Multilingual\",\"name\":\"WP Multilingual\",\"display_name\":\"WP Multilingual\",\"slug\":\"wp-multilingual\",\"version\":\"1.13\",\"new_version\":\"1.13\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-wpml\\/formidable-wpml-1.13.zip\"],\"excerpt\":\"Translate your forms into multiple languages using the Formidable-integrated WPML plugin.\",\"id\":169998,\"released\":\"2013-04-29 00:00:00\",\"categories\":[\"Business\",\"Multilingual\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-multi-language\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/wp-multilingual\\/\",\"changelog\":\"<h4>v1.13 - December 9, 2024<\\/h4>\\n<ul>\\n<li>New: Translation settings are now broken into multiple pages when the number of strings to translate exceeds the page size. Translation settings now also include a search input.<\\/li>\\n<li>New: Lookup field options can now be translated.<\\/li>\\n<li>New: Old removed options are now removed from translation settings when a form is updated.<\\/li>\\n<li>Fix: A foreach() argument must be of type array|object, null given PHP warning triggered when duplicating fields has been fixed.<\\/li>\\n<li>Fix: A database error would occur when viewing translation settings for a form with no fields.<\\/li>\\n<li>Fix: A translation issue with product field default values that would cause total field validation to fail for single products inside of conditional sections has been fixed.<\\/li>\\n<li>Fix: Fatal errors would occur when Polylang was active.<\\/li>\\n<li>Fix: An attempt to read property \\\"id\\\" on null PHP warning has been fixed.<\\/li>\\n<li>Fix: Error messages were not properly translating in some cases.<\\/li>\\n<\\/ul>\\n<h4>v1.12 - August 8, 2022<\\/h4>\\n<ul>\\n<li>New: Translations are now copied when a field or form is duplicated.<\\/li>\\n<li>New: Confirmation field validation messages can now be translated.<\\/li>\\n<li>Fix: Placeholders for Lookup dropdowns were not translating.<\\/li>\\n<li>Fix: Updated translations were not properly updating.<\\/li>\\n<\\/ul>\\n<h4>v1.11 - March 25, 2022<\\/h4>\\n<ul>\\n<li>Fix: Likert column headings were not translating properly.<\\/li>\\n<li>Fix: Incorrect and occasionally duplicate field translation options were appearing on translation pages.<\\/li>\\n<li>Fix: Formidable was appearing as an option in the WPML item dropdown, and has been removed.<\\/li>\\n<\\/ul>\\n<h4>v1.04 - October 25th, 2016<\\/h4>\\n<ul>\\n<li>Allow translation of Add\\/Remove buttons<\\/li>\\n<li>Replace some deprecated WPML function calls and constants<\\/li>\\n<li>Make sure wpml strings are updated when form is updated<\\/li>\\n<li>Do not translate default value for all field types<\\/li>\\n<li>Make sure incorrect field message is translated with ajax submit<\\/li>\\n<\\/ul>\\n<h4>v1.03.03 - March 28, 2016<\\/h4>\\n<ul>\\n<li>Send the language in the ajax url differently to prevent 404s during ajax calls. This should help with duplicate submissions.<\\/li>\\n<li>Prevent a license key from being saved for another plugin<\\/li>\\n<\\/ul>\\n<h4>v1.03.02<\\/h4>\\n<ul>\\n<li>Get updates from FormidablePro.com<\\/li>\\n<li>Make it compatible with the free version of Formidable<\\/li>\\n<li>Fix errors when Formidable or WPML are deactivated<\\/li>\\n<li>Include the current language during ajax calls<\\/li>\\n<li>Force an English start language for strings for v2.2.6 of the WPML strings plugin<\\/li>\\n<li>Fix the issue with the default language in WPML being set different than the string language<\\/li>\\n<li>If values in the form settings page changed, update them when going to the translation settings<\\/li>\\n<li>Make sure the \\\"previous\\\" label is translatable when drafts are not enabled<\\/li>\\n<li>Don\'t show strings for inactive languages<\\/li>\\n<li>Translate fields in repeating sections<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-wpml\\/formidable-wpml.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"170641\":{\"title\":\"Locations\",\"name\":\"Locations\",\"display_name\":\"Locations\",\"slug\":\"locations\",\"version\":\"2.03\",\"new_version\":\"2.03\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-locations\\/formidable-locations-2.03.zip\"],\"excerpt\":\"Populate fields with Countries, States\\/Provinces, U.S. Counties, and U.S. Cities. This data can then be used in dependent Data from Entries fields.\",\"id\":170641,\"released\":\"2014-06-21 00:00:00\",\"categories\":[\"Creator\",\"Data Collection\",\"Form Functionality\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-locations\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/locations\\/\",\"changelog\":\"<h4>v2.03 - April 20, 2023<\\/h4>\\n<ul>\\n<li>Fix: Importing cities would stop at \\\"8 remaining\\\" and never stop making requests to import additional cities.<\\/li>\\n<li>Fix: Form ids are are no longer retrieved using a deprecated function.<\\/li>\\n<li>Fix: Some city values were importing incorrectly, displaying \\\"1920\\\" as the state.<\\/li>\\n<\\/ul>\\n<h4>v2.02 - September 11, 2017<\\/h4>\\n<ul>\\n<li>Fix: Remove invalid city data.<\\/li>\\n<\\/ul>\\n<h4>v2.01 - May 10, 2016<\\/h4>\\n<ul>\\n<li>Switch to using Lookup fields<\\/li>\\n<li>Add a link to reset the locations data<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-locations\\/us_locations.php\",\"icons\":{\"1x\":\"https:\\/\\/formidableforms.com\\/wp-content\\/uploads\\/2013\\/04\\/locations.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"170645\":{\"title\":\"Zapier\",\"name\":\"Zapier\",\"display_name\":\"Zapier\",\"slug\":\"zapier\",\"version\":\"2.04\",\"new_version\":\"2.04\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-zapier\\/formidable-zapier-2.04.zip\"],\"excerpt\":\"Connect with hundreds of applications through Zapier. Automatically insert a Google spreadsheet row, tweet, or upload to Dropbox.\",\"id\":170645,\"released\":\"2014-06-04 00:00:00\",\"categories\":[\"Automation\",\"Business\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-zapier\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/zapier\\/\",\"changelog\":\"<h4>v2.04 - August 19, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<\\/ul>\\n<h4>v2.03 - March 11, 2024<\\/h4>\\n<ul>\\n<li>Fix: When polling for entries, the first entry would always get returned. Now the newest entry is returned as expected.<\\/li>\\n<\\/ul>\\n<h4>v2.02 - March 21, 2023<\\/h4>\\n<ul>\\n<li>New: Referrer checks for protected files are now allowed for Zapier requests so a protected file can be uploaded to Google Drive using a Zapier action. Protected files also need to be available to everyone or Zapier still will not have access.<\\/li>\\n<li>New: Added translation support.<\\/li>\\n<li>Fix: The \\/form API endpoint was calling a deprecated function.<\\/li>\\n<li>Fix: Prevent a fatal error when Formidable lite is inactive.<\\/li>\\n<li>Fix: The link to edit a zap would lead to a 404 page.<\\/li>\\n<li>Additional validation has been added to prevent notices for an incomplete API URL.<\\/li>\\n<li>The message to migrate will no longer be shown when no legacy Zapier posts exist.<\\/li>\\n<li>A warning will now be displayed on any temporary Zapier actions that get created for testing before publishing a zap.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-zapier\\/formidable-zapier.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"170649\":{\"title\":\"User Tracking\",\"name\":\"User Tracking\",\"display_name\":\"User Flow\",\"slug\":\"user-tracking\",\"version\":\"2.0.3\",\"new_version\":\"2.0.3\",\"location\":[\"s3.amazonaws.com\\/fp.strategy11.com\\/releases\\/formidable-user-tracking\\/formidable-user-tracking-2.0.3.zip\"],\"excerpt\":\"Track the pages a user visits and the time spent on each page prior to submitting a form.\",\"id\":170649,\"released\":\"2015-10-19 00:00:00\",\"categories\":[\"Creator\",\"Strategy11\",\"Utilities\"],\"docs\":\"\\/knowledgebase\\/formidable-user-tracking\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/user-tracking\\/\",\"changelog\":\"<h4>v2.0.3 - December 2, 2024<\\/h4>\\n<ul>\\n<li>Fix: Duplicate entry checks would usually fail with this add-on active because of the way that user journey data is stored. When performing duplicate checks with this add-on active, entry descriptions is no longer included in the query to allow for duplicate entry checks to work.<\\/li>\\n<li>Support for translations have been improved, including translated dates when viewing user flow data.<\\/li>\\n<\\/ul>\\n<h4>v2.0.2 - July 25, 2024<\\/h4>\\n<ul>\\n<li>New: This add-on is now translated in German, Spanish, French, Italian, and Brazilian Portuguese.<\\/li>\\n<li>Fix: Additional checks have been added to fix issues with user sessions starting during REST API requests. This includes an error that would appear on the Site Health page.<\\/li>\\n<li>Fix: More checks have been added to avoid starting sessions when running CLI commands.<\\/li>\\n<\\/ul>\\n<h4>v2.0.1 - June 6, 2024<\\/h4>\\n<ul>\\n<li>New: User flow summaries can now be collapsed and opened by date.<\\/li>\\n<li>New: Forms with no title will now display as (no title) in the user flow summary.<\\/li>\\n<li>Fix: Session start logic has been moved to help avoid a headers already sent PHP warning on admin pages.<\\/li>\\n<li>Fix: A bug has been fixed that would cause incorrect user flow duration values.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-user-tracking\\/formidable-user-tracking.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"170655\":{\"title\":\"Mailchimp\",\"name\":\"Mailchimp\",\"display_name\":\"Mailchimp\",\"slug\":\"mailchimp\",\"version\":\"2.10\",\"new_version\":\"2.10\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-mailchimp\\/formidable-mailchimp-2.10.zip\"],\"excerpt\":\"Get on the path to more leads in minutes. Add and update leads in a Mailchimp mailing list when a form is submitted.\",\"id\":170655,\"released\":\"2013-10-17 00:00:00\",\"categories\":[\"Creator\",\"Email &amp; SMS Marketing\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-mailchimp\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/mailchimp\\/\",\"changelog\":\"<h4>v2.10 - June 18, 2025<\\/h4>\\n<ul>\\n<li>New: Mailchimp actions can now be delayed using form action automation.<\\/li>\\n<li>Fix: When a subscriber re-subscribes and double opt-in was enabled, the subscriber status would not update to subscribed.<\\/li>\\n<\\/ul>\\n<h4>v2.09 - November 5, 2024<\\/h4>\\n<ul>\\n<li>New: Mailchimp field data is now stored and re-used in the database to optimize Mailchimp actions. Previously two requests were required when subscribing, causing performance issues.<\\/li>\\n<li>New: When a Name field is mapped to a Mailchimp action, the (First) and (Last) descriptions are now included in the dropdown option label to make it more clear how the values are mapped.<\\/li>\\n<\\/ul>\\n<h4>v2.08 - September 3, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese. This does not include dynamic fields loaded from Mailchimp\'s API.<\\/li>\\n<li>New: The field limit retrieved from the Mailchimp API has been increased from 30 to 100.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-mailchimp\\/formidable-mailchimp.php\",\"icons\":{\"1x\":\"https:\\/\\/formidableforms.com\\/wp-content\\/uploads\\/2013\\/04\\/mailchimp.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"172715\":{\"title\":\"PayPal Basic\",\"name\":\"PayPal Basic\",\"display_name\":\"PayPal Basic\",\"slug\":\"paypal-standard-single-payments\",\"version\":\"3.08\",\"new_version\":\"3.08\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-paypal\\/formidable-paypal-3.08.zip\"],\"excerpt\":\"\",\"id\":172715,\"released\":\"2015-10-21 12:20:35\",\"categories\":[\"Ecommerce\",\"Strategy11\"],\"docs\":\"\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/paypal-standard-single-payments\\/\",\"changelog\":\"<h4>v3.02 - September 14, 2018<\\/h4>\\n<ul>\\n<li>Merge the older grandfathered PayPal addon with the updated version.<\\/li>\\n<\\/ul>\\n<h4>v2.04.07 - January 25, 2015<\\/h4>\\n<ul>\\n<li>Allow amounts with . for thousands and , for decimal. If a . is used in the decimal place for the amount when the currency uses a , make it work anyway<\\/li>\\n<li>Redirect to PayPal correctly without Pro<\\/li>\\n<li>Make sure email setting is trimmed before comparing<\\/li>\\n<li>Add download ID to make sure correct license is used<\\/li>\\n<\\/ul>\\n<h4>v2.04.06 - November 17, 2015<\\/h4>\\n<ul>\\n<li>Prevent errors when updating Formidable<\\/li>\\n<\\/ul>\\n<h4>v2.04.05<\\/h4>\\n<ul>\\n<li>Format decimals with . to allow float to work correctly<\\/li>\\n<li>Get updates from FormidablePro.com<\\/li>\\n<\\/ul>\\n<h4>v2.04.04<\\/h4>\\n<ul>\\n<li>Allow the amount to be included in the \\\"other\\\" option<\\/li>\\n<li>Modify the user-agent in the IPN verification to prevent errors from PayPal<\\/li>\\n<\\/ul>\\n<h4>v2.04.03<\\/h4>\\n<ul>\\n<li>Save the IPN parameters with the payment in the format that allows for multiple IPN notifications<\\/li>\\n<li>Fix sending users to Paypal when 2.x is installed, but the old settings haven\'t been moved to a form action<\\/li>\\n<li>Increased security related to XSS add_query_arg vulnerability<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"paypal-standard-single-payments\\/paypal-standard-single-payments.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"173984\":{\"title\":\"User Registration\",\"name\":\"User Registration\",\"display_name\":\"User Registration\",\"slug\":\"user-registration\",\"version\":\"3.0.1\",\"new_version\":\"3.0.1\",\"location\":[\"s3.amazonaws.com\\/fp.strategy11.com\\/releases\\/formidable-registration\\/formidable-registration-3.0.1.zip\"],\"excerpt\":\"Give new users access to your site quickly and painlessly. Plus edit profiles and login from the front end.\",\"id\":173984,\"released\":\"2011-12-21 00:00:00\",\"categories\":[\"Business\",\"Data Collection\",\"Form Functionality\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/user-registration\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/user-registration\\/\",\"changelog\":\"<h4>v3.0.1 - January 27, 2025<\\/h4>\\n<ul>\\n<li>New: Login forms will now use the label position setting used in the applied Formidable style added using the class shortcode option.<\\/li>\\n<li>New: An appropriate error message will now be shown the reset password email fails to send because of an email deliverability issue.<\\/li>\\n<li>New: Some changes have been made to support the SiteGround Security Optimizer plugin\'s custom login URL functionality. A new frmreg_supports_alternative_login_url filter has been added to enable an alternative URL for cases when wp-login is blocked by another plugin.<\\/li>\\n<li>Fix: Fields used in registration actions would fail required validation checks when inside of a conditionally hidden section.<\\/li>\\n<li>Fix: A fatal error would occur when unexpected array redirect data was submitted to the login form.<\\/li>\\n<li>Fix: The hook used to load translations has been updated to improve compatibility with WordPress 6.7+.<\\/li>\\n<li>The setting to automatically log in users who submit this form was been removed from repeated registration actions.<\\/li>\\n<\\/ul>\\n<h4>v3.0 - October 8, 2024<\\/h4>\\n<ul>\\n<li>New: Registration actions now include the option to run a registration action for each entry of a repeater. This allows you to create multiple users with a single form.<\\/li>\\n<li>New: When a Name field is mapped to a User Registration action, the (First) and (Last) descriptions are now included in the dropdown option label to make it more clear how the values are mapped.<\\/li>\\n<li>New: Missing for attributes have been added to user meta inputs to help improve accessibility.<\\/li>\\n<li>Fix: In some cases, multiple activation success messages would appear. A check has been added to limit the number of related success messages to one.<\\/li>\\n<li>Additional validation has been added when saving registration page settings to help prevent issues where shortcodes are later removed from previously valid login pages.<\\/li>\\n<li>Some references to old deprecated Pro functions have been updated.<\\/li>\\n<\\/ul>\\n<h4>v2.13 - April 4, 2024<\\/h4>\\n<ul>\\n<li>New: User moderation redirects now support a new option to Redirect to a URL.<\\/li>\\n<li>New: Links and forms have been updated to use the site URL for logging in instead of the network site URL.<\\/li>\\n<li>New: The &#091;frm-login] shortcode now support several new options including register_link, label_register, class_register for adding registration links to login forms.<\\/li>\\n<li>New: The logout_redirect option used in &#091;frm-login] shortcodes now supports numeric page ID values.<\\/li>\\n<li>New: &#091;frm-reset-password] shortcodes now support new password_strength=\\\"1\\\" and password_visibility_toggle=\\\"1\\\" options.<\\/li>\\n<li>Fix: Errors messages will now show on page load when using the slide=1 option with a &#091;frm-login] shortcode.<\\/li>\\n<li>Several old deprecated functions have been removed.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-registration\\/formidable-registration.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"registration, user registration, register\",\"is_new\":false},\"174006\":{\"title\":\"WooCommerce\",\"name\":\"WooCommerce\",\"display_name\":\"WooCommerce\",\"slug\":\"woocommerce\",\"version\":\"1.14\",\"new_version\":\"1.14\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-woocommerce\\/formidable-woocommerce-1.14.zip\"],\"excerpt\":\"Are your WooCommerce product forms too basic? Add custom fields to a product form and collect more data when it is added to the cart.\",\"id\":174006,\"released\":\"2016-01-19 00:00:00\",\"categories\":[\"Ecommerce\",\"Elite\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-woocommerce\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/woocommerce\\/\",\"changelog\":\"\",\"plugin\":\"formidable-woocommerce\\/formidable-woocommerce.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"180495\":{\"title\":\"Highrise\",\"name\":\"Highrise\",\"display_name\":\"Highrise\",\"slug\":\"highrise\",\"version\":\"1.06\",\"new_version\":\"1.06\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-highrise\\/formidable-highrise-1.06.zip\"],\"excerpt\":\"Capture leads in your WordPress contact forms, and save them in your Highrise CRM account too.\",\"id\":180495,\"released\":\"2013-12-12 00:00:00\",\"categories\":[\"Creator\",\"CRM\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-highrise\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/highrise\\/\",\"changelog\":\"<h4>v1.06 - February 29, 2016<\\/h4>\\n<ul>\\n<li>Send the custom fields correctly to Highrise<\\/li>\\n<\\/ul>\\n<h4>v1.05 - February 23, 2016<\\/h4>\\n<ul>\\n<li>Fix email field settings in the Highrise action<\\/li>\\n<li>Make sure the license key is a Highrise license<\\/li>\\n<\\/ul>\\n<h4>v1.04 - February 9, 2016<\\/h4>\\n<ul>\\n<li>Added options to separate out address fields. City, State, Zip, and Country can now be mapped separately.<\\/li>\\n<li>Fixed PHP7 warnings<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-highrise\\/formidable-highrise.php\",\"icons\":{\"1x\":\"https:\\/\\/formidableforms.com\\/wp-content\\/uploads\\/2012\\/01\\/highrise.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"185013\":{\"title\":\"Bootstrap Modal\",\"name\":\"Bootstrap Modal\",\"display_name\":\"Bootstrap Modal\",\"slug\":\"bootstrap-modal\",\"version\":\"3.0.3\",\"new_version\":\"3.0.3\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-modal\\/formidable-modal-3.0.3.zip\"],\"excerpt\":\"Open forms, views, other shortcodes, or sections of content in a Bootstrap popup.\",\"id\":185013,\"released\":\"2015-08-26 00:00:00\",\"categories\":[\"Creator\",\"Form Design &amp; Display\",\"Form Functionality\",\"Strategy11\"],\"docs\":\"https:\\/\\/formidableforms.com\\/knowledgebase\\/bootstrap-modal\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/bootstrap-modal\\/\",\"changelog\":\"<h4>v3.0.3 - April 30, 2025<\\/h4>\\n<ul>\\n<li>New: An info message shows in the modal if a form is used there without AJAX submission enabled.<\\/li>\\n<li>Fix: JS error when Formidable Forms isn\'t activated.<\\/li>\\n<li>Fix: A duplicated background color setting is removed.<\\/li>\\n<\\/ul>\\n<h4>v3.0.2 - December 11, 2023<\\/h4>\\n<ul>\\n<li>New: The modal block button will now have a default \\\"Click here\\\" text instead of an empty input to make quick testing easier.<\\/li>\\n<li>New: The modal close button will now longer appear in the block preview as it was getting in the way and served no purpose.<\\/li>\\n<li>New: The modal block has been updated to work better with white label settings.<\\/li>\\n<li>Fix: The autocomplete popup from the Formidable Geolocation add on would not appear inside of a Bootstrap modal because of a z-index issue.<\\/li>\\n<\\/ul>\\n<h4>v3.0.1 - June 26, 2023<\\/h4>\\n<ul>\\n<li>Fix: Modals were hidden when the Formidable Bootstrap add on was also active.<\\/li>\\n<li>Fix: Modals made with the [[frmmodal-content]] shortcode were missing a backdrop.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-modal\\/formidable-modal.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"modal, popup\",\"is_new\":false},\"209561\":{\"title\":\"Polylang\",\"name\":\"Polylang\",\"display_name\":\"Polylang\",\"slug\":\"polylang\",\"version\":\"1.14\",\"new_version\":\"1.14\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-polylang\\/formidable-polylang-1.14.zip\"],\"excerpt\":\"Create bilingual or multilingual forms with help from Polylang.\",\"id\":209561,\"released\":\"2016-01-22 00:00:00\",\"categories\":[\"Business\",\"Multilingual\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/formidable-polylang\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/polylang\\/\",\"changelog\":\"<h4>v1.14 - June 2, 2025<\\/h4>\\n<ul>\\n<li>Fix: Saving Polylang translations would trigger a fatal error when using the newest version of Polylang.<\\/li>\\n<li>Fix: Checkbox fields would fail option validation when the checkbox options were translated and the checkbox field was on a page other than the last page.<\\/li>\\n<\\/ul>\\n<h4>v1.13 - October 29, 2024<\\/h4>\\n<ul>\\n<li>New: The text for previous buttons used in multiple page forms is now translatable.<\\/li>\\n<li>New: The text for the start and continue buttons used in conversational forms are now translatable.<\\/li>\\n<\\/ul>\\n<h4>v1.12 - August 19, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<li>Fix: A trim(): Passing null to parameter deprecated message when viewing a form has been fixed.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-polylang\\/frm-poly.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"310430\":{\"title\":\"Stripe\",\"name\":\"Stripe\",\"display_name\":\"Stripe\",\"slug\":\"stripe\",\"version\":\"3.1.9\",\"new_version\":\"3.1.9\",\"location\":[\"fp.strategy11.com\\/releases\\/formidable-stripe\\/formidable-stripe-3.1.9.zip\"],\"excerpt\":\"Any Formidable forms on your site can accept credit card payments without users ever leaving your site.\",\"id\":310430,\"released\":\"2016-04-26 00:00:00\",\"categories\":[\"Business\",\"Ecommerce\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/stripe\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/stripe\\/\",\"changelog\":\"<h4>v3.1.9 - March 11, 2026<\\/h4>\\n<ul>\\n<li>New: Additional validation has been added to prevent people from manipulating amount values when making Stripe Link payments.<\\/li>\\n<li>New: Missing payment fields are automatically inserted into forms when a payment action is saved.<\\/li>\\n<li>New: A new `frm_strp_new_subscription` filter has been added, similar to the `frm_strp_new_charge` filter. Note that this filter does not apply to Stripe Link payments.<\\/li>\\n<li>Fix: Changes that trigger for successful payments would trigger incorrectly for pending 3D secure payments.<\\/li>\\n<li>Fix: An Undefined array key \\\"currency\\\" PHP Warning has been fixed.<\\/li>\\n<li>Fix: Multiple customer objects would get created for Stripe Link recurring payments.<\\/li>\\n<li>Fix: An Undefined property: stdClass::$item_key PHP Warning has been fixed.<\\/li>\\n<li>Fix: A conditionally shown payment gateway wouldn\'t correctly reset to its default value, causing payments not to trigger.<\\/li>\\n<\\/ul>\\n<h4>v3.1.8 - June 11, 2025<\\/h4>\\n<ul>\\n<li>Fix: A fatal error would occur when using both Authorize.Net v2.0.4 and this Stripe add-on.<\\/li>\\n<li>Fix: Stripe scripts would incorrectly load in cases where the Stripe gateway was not selected.<\\/li>\\n<li>Fix: The Stripe link toggle would appear in cases where the Stripe gateway was not selected.<\\/li>\\n<\\/ul>\\n<h4>v3.1.7 - May 6, 2025<\\/h4>\\n<ul>\\n<li>New: Stripe payment fields will now apply border radius styles to match styling better.<\\/li>\\n<li>New: Stripe payment field label styling has been updated to better reflect label padding style settings.<\\/li>\\n<li>New: Stripe payment fields will now use the input weight style setting to look more consistent with other fields.<\\/li>\\n<li>New: Stripe payment fields now support the font family style setting.<\\/li>\\n<li>New: A new layout setting has been added to Stripe settings that adds support for the accordion layout.<\\/li>\\n<li>New: A new frm_stripe_appearance_rules filter has been added to make it possible to match a Stripe link field to a theme.<\\/li>\\n<li>Fix: The PayPal gateway option wouldn\'t appear on the edit payment page.<\\/li>\\n<li>Fix: A dynamic trial period based on a shortcode would fallback to a 1 day trial when it should be 0.<\\/li>\\n<li>Fix: An in-progress form entry created using the Form Abandonment add-on would not properly submit when using a Stripe action.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-stripe\\/formidable-stripe.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"326042\":{\"title\":\"Form Action Automation\",\"name\":\"Form Action Automation\",\"display_name\":\"Form Action Automation\",\"slug\":\"autoresponder\",\"version\":\"2.09\",\"new_version\":\"2.09\",\"location\":[\"fp.strategy11.com\\/releases\\/autoresponder\\/formidable-autoresponder-2.09.zip\"],\"excerpt\":\"Schedule email notifications, SMS messages, and API actions.\",\"id\":326042,\"released\":\"2016-09-21 00:00:00\",\"categories\":[\"Automation\",\"Elite\",\"Marketing\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/schedule-autoresponder\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/autoresponder\\/\",\"changelog\":\"<h4>v2.09 - June 18, 2025<\\/h4>\\n<ul>\\n<li>New: Added support for automating more types of form actions.<\\/li>\\n<\\/ul>\\n<h4>v2.08 - August 13, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<\\/ul>\\n<h4>v2.07 - April 29, 2024<\\/h4>\\n<ul>\\n<li>New: The frm_autoresponder_time filter is now always applied. Previously this filter was only used when date or time fields were defined as the send date setting.<\\/li>\\n<li>New: Strings used in this plugin can now be translated.<\\/li>\\n<li>Fix: A bug has been fixed that would strip &#091;] shortcode characters after duplicating a form action with dashes in the value like a date format.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-autoresponder\\/formidable-autoresponder.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"automate, automation\",\"is_new\":false},\"337527\":{\"title\":\"Authorize.net AIM\",\"name\":\"Authorize.net AIM\",\"display_name\":\"Authorize.net AIM\",\"slug\":\"authorize-net-aim\",\"version\":\"2.04\",\"new_version\":\"2.04\",\"location\":[\"fp.strategy11.com\\/releases\\/authorize-net\\/formidable-authorize-net-2.04.zip\"],\"excerpt\":\"Accept one-time payments directly on your site, using Authorize.net AIM.\",\"id\":337527,\"released\":\"2016-04-29 00:00:00\",\"categories\":[\"Ecommerce\",\"Elite\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/authorize-net-aim\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/authorize-net-aim\\/\",\"changelog\":\"<h4>v2.04 - June 5, 2025<\\/h4>\\n<ul>\\n<li>New: A new &#091;frm-payment] shortcode has been added. This can be used to display quick details about a payment for a given entry ID. For example, &#091;frm-payment entry=&#091;id] show=amount] can be used in a view to get the payment amount.<\\/li>\\n<li>New: Screen reader text has been updated to the payments admin page to improve accessibility.<\\/li>\\n<li>Fix: Repeated fields would disappear after reloading a form as the result of a failed payment.<\\/li>\\n<li>Fix: Shipping information would not appear on load unless shipping was already enabled.<\\/li>\\n<li>Fix: An autoload issue would result in fatal errors on some sites.<\\/li>\\n<li>Fix: A Creation of dynamic property FrmAuthNetApi::$endpoint is deprecated PHP deprecation message that happens in PHP 8.2+ has been fixed.<\\/li>\\n<li>Fix: The PayPal gateway option wouldn\'t appear on the edit payment page.<\\/li>\\n<li>When a Name field is mapped to a payment action, the (First) and (Last) descriptions are now included in the dropdown option label to make it more clear how the values are mapped.<\\/li>\\n<\\/ul>\\n<h4>v2.03 - April 24, 2024<\\/h4>\\n<ul>\\n<li>Fix: A FrmTransActionsController not found fatal error related to autoloading occuring on some server configurations has been fixed.<\\/li>\\n<\\/ul>\\n<h4>v2.02 - March 7, 2022<\\/h4>\\n<ul>\\n<li>New: Name fields will now automatically map the proper first and last name values when sending to Authorize.net.<\\/li>\\n<li>New: Set the default currency to the one selected in global settings.<\\/li>\\n<li>New: Added additional currencies from Pro.<\\/li>\\n<li>Fix: Payments would not work if the amount specified was formatted as currency.<\\/li>\\n<li>Fix: Prevent a fatal error that happens in PHP8 when filling payment information.<\\/li>\\n<li>Fix: Expire dates were not properly calculating.<\\/li>\\n<li>Fix: Some echecks were not getting approved.<\\/li>\\n<li>Fix: Updated incorrect text domains.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-authorize-net\\/formidable-authorize-net.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"Authorize.net\",\"is_new\":false},\"11927748\":{\"title\":\"Logs\",\"name\":\"Logs\",\"display_name\":\"Logs\",\"slug\":\"logs\",\"version\":\"1.0.4\",\"new_version\":\"1.0.4\",\"location\":[\"fp.strategy11.com\\/releases\\/logs\\/formidable-logs-1.0.4.zip\"],\"excerpt\":\"See your API requests along with their responses from add-ons including Zapier, Formidable API Webhooks, Salesforce and more.\",\"id\":11927748,\"released\":\"2016-12-19 00:00:00\",\"categories\":[\"Basic\",\"Strategy11\",\"Utilities\"],\"docs\":\"https:\\/\\/formidableforms.com\\/knowledgebase\\/logging\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/logs\\/\",\"changelog\":\"\",\"plugin\":\"formidable-logs\\/formidable-logs.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"19366992\":{\"title\":\"Formidable Pro Elite Package\",\"name\":\"Formidable Pro Elite Package\",\"display_name\":\"Formidable Pro Elite Package\",\"slug\":\"formidable-pro-enterprise-package\",\"version\":\"\",\"new_version\":\"\",\"location\":[],\"excerpt\":\"\",\"id\":19366992,\"released\":\"2017-09-01 12:09:38\",\"categories\":[\"Strategy11\"],\"docs\":\"\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/formidable-pro-enterprise-package\\/\",\"changelog\":\"\",\"plugin\":\"formidable-pro-enterprise-package\\/formidable-pro-enterprise-package.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"19366995\":{\"title\":\"Formidable Pro Business Package\",\"name\":\"Formidable Pro Business Package\",\"display_name\":\"Formidable Pro Business Package\",\"slug\":\"formidable-pro-small-business-package\",\"version\":\"\",\"new_version\":\"\",\"location\":[],\"excerpt\":\"\",\"id\":19366995,\"released\":\"2017-09-01 12:09:09\",\"categories\":[\"Strategy11\"],\"docs\":\"\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/formidable-pro-small-business-package\\/\",\"changelog\":\"\",\"plugin\":\"formidable-pro-small-business-package\\/formidable-pro-small-business-package.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"19367001\":{\"title\":\"Formidable Pro Creator Package\",\"name\":\"Formidable Pro Creator Package\",\"display_name\":\"Formidable Pro Creator Package\",\"slug\":\"formidable-pro-professional-package\",\"version\":\"\",\"new_version\":\"\",\"location\":[],\"excerpt\":\"\",\"id\":19367001,\"released\":\"2017-09-01 12:10:24\",\"categories\":[\"Strategy11\"],\"docs\":\"\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/formidable-pro-professional-package\\/\",\"changelog\":\"\",\"plugin\":\"formidable-pro-professional-package\\/formidable-pro-professional-package.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"19367654\":{\"title\":\"Formidable Pro Single Site\",\"name\":\"Formidable Pro Single Site\",\"display_name\":\"Formidable Pro Single Site\",\"slug\":\"formidable-pro-single-site\",\"version\":\"\",\"new_version\":\"\",\"location\":[],\"excerpt\":\"\",\"id\":19367654,\"released\":\"2017-09-01 13:36:16\",\"categories\":[\"Strategy11\"],\"docs\":\"\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/formidable-pro-single-site\\/\",\"changelog\":\"\",\"plugin\":\"formidable-pro-single-site\\/formidable-pro-single-site.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"20247260\":{\"title\":\"Datepicker Options\",\"name\":\"Datepicker Options\",\"display_name\":\"Datepicker Options\",\"slug\":\"datepicker-options\",\"version\":\"3.0\",\"new_version\":\"3.0\",\"location\":[\"fp.strategy11.com\\/releases\\/dates\\/formidable-dates-3.0.zip\"],\"excerpt\":\"Add more options to date fields in your forms for so only the dates you choose can be chosen.\",\"id\":20247260,\"released\":\"2018-07-30 00:00:00\",\"categories\":[\"Business\",\"Form Functionality\",\"Strategy11\"],\"docs\":\"\\/knowledgebase\\/datepicker-options\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/datepicker-options\\/\",\"changelog\":\"<h4>v3.0 - September 9, 2025<\\/h4>\\n<ul>\\n<li>New: Date fields now support a new Date Range setting. When enabled, a new End Date field will be added and linked to the Start Date field. Note that this requires version 6.24 of Formidable Pro.<\\/li>\\n<li>New: The settings for Date Fields have been updated. Blackout Dates and Exceptions Dates now use a new type of input.<\\/li>\\n<li>Fix: Additional checks have been added to help prevent unexpected errors when using date calculations and editing in-place.<\\/li>\\n<\\/ul>\\n<h4>v2.1 - February 24, 2025<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<li>Fix: Inline date fields would not initialize properly in new forms that appears after a form is completed when submitting with AJAX.<\\/li>\\n<li>Fix: The hook used to load translations has been updated to improve compatibility with WordPress 6.7+.<\\/li>\\n<\\/ul>\\n<h4>v2.0.4 - March 28, 2024<\\/h4>\\n<ul>\\n<li>New: Blocked dates are no longer counted in &#091;date_calc] shortcode calculations by default when using the format=\\\"days\\\" option. In order to count blocked out dates, you must now include a new count_blackout_dates=\\\"1\\\" option.<\\/li>\\n<li>New: The strings used in this add-on can now be translated.<\\/li>\\n<li>Fix: Date calculations would trigger an error pop up on the edit entry admin page.<\\/li>\\n<li>Fix: Some date field validation checks would fail when sending a date value in Y-m-d format instead of the global date format setting.<\\/li>\\n<li>Fix: When validating if a date value is greater than or less than today, the value for today was based on the UTC timezone instead of the server timezone.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-dates\\/formidable-dates.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"datepicker\",\"is_new\":false},\"20266559\":{\"title\":\"Salesforce\",\"name\":\"Salesforce\",\"display_name\":\"Salesforce\",\"slug\":\"salesforce\",\"version\":\"2.05\",\"new_version\":\"2.05\",\"location\":[\"fp.strategy11.com\\/releases\\/salesforce\\/formidable-salesforce-2.05.zip\"],\"excerpt\":\"Add new contacts and leads into your Salesforce CRM directly from the WordPress forms on your site.\",\"id\":20266559,\"released\":\"2018-05-31 00:00:00\",\"categories\":[\"CRM\",\"Elite\"],\"docs\":\"https:\\/\\/formidableforms.com\\/knowledgebase\\/salesforce-forms\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/salesforce\\/\",\"changelog\":\"<h4>v2.06 - November 1, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<li>New: Users are no longer required to replace the %3D%3D text copied from the end of their Authentication code when authenticating, making it easier to get set-up.<\\/li>\\n<\\/ul>\\n<h4>v2.05 - June 11, 2024<\\/h4>\\n<ul>\\n<li>New: Field dropdowns have been updated to enable support for repeater actions.<\\/li>\\n<li>Fix: Authentication errors would not visibly appear, making it difficult to troubleshoot authentication issues.<\\/li>\\n<li>Fix: A Trying to access array offset on value of type bool PHP Warning has been fixed.<\\/li>\\n<li>Fix: An Implicit conversion from float to int loses precision PHP Deprecated message has been fixed.<\\/li>\\n<li>Fix: An Automatic conversion of false to array is deprecated PHP Deprecated message has been fixed.<\\/li>\\n<\\/ul>\\n<h4>v2.04 - December 10, 2019<\\/h4>\\n<ul>\\n<li>New: Show Salesforce Authentication errors on the global settings page<\\/li>\\n<li>Add icon in global settings<\\/li>\\n<li>Use font icon instead of image in form action<\\/li>\\n<li>Remove debug mode in favor of logging<\\/li>\\n<li>Tweak: Clear the settings cache with a link instead of ajax for more reliable cache clearing<\\/li>\\n<li>Fix: Updating data in Salesforce wasn\'t working correctly<\\/li>\\n<li>Fix: There was an error when Formidable was disabled<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-salesforce\\/formidable-salesforce.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"20781560\":{\"title\":\"MailPoet Newsletters\",\"name\":\"MailPoet Newsletters\",\"display_name\":\"MailPoet Newsletters\",\"slug\":\"mailpoet-newsletters\",\"version\":\"1.04\",\"new_version\":\"1.04\",\"location\":[\"fp.strategy11.com\\/releases\\/mailpoet\\/formidable-mailpoet-1.04.zip\"],\"excerpt\":\"Send WordPress newsletters from your own site with MailPoet. And use Formidable to for your newsletter signup forms.\",\"id\":20781560,\"released\":\"2018-06-05 00:00:00\",\"categories\":[\"Creator\",\"Email &amp; SMS Marketing\"],\"docs\":\"https:\\/\\/formidableforms.com\\/knowledgebase\\/mailpoet-newsletter-signup-forms\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/mailpoet-newsletters\\/\",\"changelog\":\"<h4>v1.04 - August 20, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<\\/ul>\\n<h4>v1.03 - June 11, 2024<\\/h4>\\n<ul>\\n<li>New: Field dropdowns have been updated to enable support for repeater actions.<\\/li>\\n<\\/ul>\\n<h4>v1.02 - July 12, 2022<\\/h4>\\n<ul>\\n<li>New: Added support for logging MailPoet subscriptions when the Logs add on is active.<\\/li>\\n<li>New: Name fields will now automatically map the proper first and last name values when sending to MailPoet.<\\/li>\\n<li>Fix: Users could not subscribe to multiple lists when the active language was not in English because the error check was specific to language.<\\/li>\\n<li>Fix: Prevent a warning when sending data with MailPoet action.<\\/li>\\n<li>Fix: Nothing would get sent when a user id field was set to something other than a name or email option.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-mailpoet\\/formidable-mailpoet.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"20790298\":{\"title\":\"Active Campaign\",\"name\":\"Active Campaign\",\"display_name\":\"ActiveCampaign\",\"slug\":\"activecampaign-wordpress-plugin\",\"version\":\"1.11\",\"new_version\":\"1.11\",\"location\":[\"fp.strategy11.com\\/releases\\/activecampaign\\/formidable-activecampaign-1.11.zip\"],\"excerpt\":\"Add contacts to any ActiveCampaign list from your WordPress forms.\",\"id\":20790298,\"released\":\"2018-07-05 00:00:00\",\"categories\":[\"Elite\",\"Email &amp; SMS Marketing\"],\"docs\":\"https:\\/\\/formidableforms.com\\/knowledgebase\\/activecampaign-forms\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/activecampaign-wordpress-plugin\\/\",\"changelog\":\"<h4>v1.11 - August 12, 2025<\\/h4>\\n<ul>\\n<li>Update translation strings.<\\/li>\\n<li>New: Show (First) and (Last) along with field name when mapping name fields.<\\/li>\\n<li>New: Add Formidable Form Action Automation support.<\\/li>\\n<li>Fix: Function _load_textdomain_just_in_time was called incorrectly.<\\/li>\\n<\\/ul>\\n<h4>v1.10 - June 11, 2024<\\/h4>\\n<ul>\\n<li>New: Field dropdowns have been updated to enable support for repeater actions.<\\/li>\\n<\\/ul>\\n<h4>v1.09 - March 25, 2024<\\/h4>\\n<ul>\\n<li>New: The strings used in this add-on can now be translated.<\\/li>\\n<li>Fix: An Uncaught Error: Class \\\"FrmFormAction\\\" not found fatal error has been fixed that happens on WPEngine hosted servers using PHP 8.2.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-activecampaign\\/formidable-activecampaign.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"ActiveCampaign\",\"is_new\":false},\"20811871\":{\"title\":\"HubSpot\",\"name\":\"HubSpot\",\"display_name\":\"HubSpot\",\"slug\":\"hubspot-wordpress\",\"version\":\"2.0.2\",\"new_version\":\"2.0.2\",\"location\":[\"fp.strategy11.com\\/releases\\/hubspot\\/formidable-hubspot-2.0.2.zip\"],\"excerpt\":\"HubSpot is a complete CRM platform with tools for increased leads, accelerated sales, or streamlined customer service.\",\"id\":20811871,\"released\":\"2018-09-04 00:00:00\",\"categories\":[\"CRM\",\"Elite\"],\"docs\":\"https:\\/\\/formidableforms.com\\/knowledgebase\\/hubspot-forms\\/\",\"link\":\"https:\\/\\/formidableforms.com\\/downloads\\/hubspot-wordpress\\/\",\"changelog\":\"<h4>v2.0.2 - September 23, 2024<\\/h4>\\n<ul>\\n<li>New: This plugin now includes translations for French, Spanish, Italian, German, Japanese and Brazilian Portuguese.<\\/li>\\n<li>New: When a Name field is mapped to a HubSpot action, the (First) and (Last) descriptions are now included in the dropdown option label to make it more clear how the values are mapped.<\\/li>\\n<\\/ul>\\n<h4>v2.0.1 - June 11, 2024<\\/h4>\\n<ul>\\n<li>New: Field dropdowns have been updated to enable support for repeater actions.<\\/li>\\n<li>New: The request sent to get lists from Hubspot will now only query for static lists, allowing each request to get more lists without hitting page limits.<\\/li>\\n<li>New: If there are more than 250 static contact lists, multiple requests will be made to get the full list of static Hubspot contact lists.<\\/li>\\n<li>Fix: European private app access tokens would fail to validate.<\\/li>\\n<\\/ul>\\n<h4>v2.0 - March 27, 2023<\\/h4>\\n<ul class=\\\"p-rich_text_list p-rich_text_list__bullet\\\" data-stringify-type=\\\"unordered-list\\\" data-indent=\\\"0\\\" data-border=\\\"0\\\">\\n<li data-stringify-indent=\\\"0\\\" data-stringify-border=\\\"0\\\">New: Added a new OAuth2 authentication method.<\\/li>\\n<li data-stringify-indent=\\\"0\\\" data-stringify-border=\\\"0\\\">New: While using the new OAuth2 authentication, contacts will now get deleted with a webhook after they are removed from HubSpot for GDPR compliance.<\\/li>\\n<li data-stringify-indent=\\\"0\\\" data-stringify-border=\\\"0\\\">New: Added translation support.<\\/li>\\n<li data-stringify-indent=\\\"0\\\" data-stringify-border=\\\"0\\\">New: Improved error handling when inputting an invalid Private App Access token.<\\/li>\\n<li data-stringify-indent=\\\"0\\\" data-stringify-border=\\\"0\\\">Fix: List data would display as an error after successfully authenticating HubSpot and after successfully clearing the cache.<\\/li>\\n<li data-stringify-indent=\\\"0\\\" data-stringify-border=\\\"0\\\">Fix: HubSpot access tokens would fail to save while the Geolocation add on was also active.<\\/li>\\n<li data-stringify-indent=\\\"0\\\" data-stringify-border=\\\"0\\\">Deprecated HubSpot API Keys are no longer supported.<\\/li>\\n<\\/ul>\\n\",\"plugin\":\"formidable-hubspot\\/formidable-hubspot.php\",\"icons\":{\"1x\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/icon-256x256.png\"},\"banners\":{\"high\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\",\"low\":\"https:\\/\\/ps.w.org\\/formidable\\/assets\\/banner-1544x500.png\"},\"search_terms\":\"\",\"is_new\":false},\"20813244\":{\"title\":\"GetResponse\",\"name\":\"GetResponse\",\"display_name\":\"GetResponse\",\"slug\":\"getresponse-wordpress-plugin\",\"version\":\"1.07\",\"new_version\":\"1.07\",\"location\":[\"fp.strategy11.com\\/releases\\/getresponse\\/formidable-getresponse-1.07.zip\"],\"excerpt\":\"Collect leads in WordPress forms and automatically add them in GetResponse. Then trigger automatic emails and other GetResponse marketing automations.\",\"id\":20813244,\"released\":\"2018-09-06 00:00:00\",\"categories\":[\"Business\",\"Email &amp; SMS Marketing