INSERT INTO `wp_postmeta` VALUES (127,43,'titre','Médias et citoyens');
INSERT INTO `wp_postmeta` VALUES (128,43,'_titre','field_olthem_thm_titre');
INSERT INTO `wp_postmeta` VALUES (129,43,'descriptif_desktop','J’en peux plus de toutes ces news si déprimantes qui disent tout et n’importe quoi ! Je rêve d’autre chose…\r\n\r\nJ’veux de la vraie info, des trucs qui me parlent, pas un défilé putaclic…\r\nLes médias, sont vraiment libres ? Parfois j’ai des doutes…\r\nEt puis c’est quoi la place des citoyens là-dedans ? Des gens comme toi et moi…\r\nFaudrait qu’on en parle ensemble, journalistes et citoyens réunis…qu’on se mette toutes et tous autour de la table pour avancer, parce que là, ça urge !');
INSERT INTO `wp_postmeta` VALUES (130,43,'_descriptif_desktop','field_olthem_thm_descriptif_desktop');
INSERT INTO `wp_postmeta` VALUES (131,43,'descriptif_mobile','J’veux de la vraie info, des trucs qui me parlent... Les médias, sont vraiment libres ? Parfois j’ai des doutes… Faudrait qu’on en parle ensemble, journalistes et citoyens réunis…');
