INSERT INTO `wp_postmeta` VALUES (148,39,'titre','Polarisation & Nuance');
INSERT INTO `wp_postmeta` VALUES (149,39,'_titre','field_olthem_thm_titre');
INSERT INTO `wp_postmeta` VALUES (150,39,'descriptif_desktop','Une question qui traverse notre époque et nos usages numériques : la polarisation des opinions sur les réseaux sociaux, et la rarification progressive de la nuance dans les débats en ligne. Prendre le temps de ralentir, dans un environnement qui pousse à réagir vite, fort, parfois sans recul. Car si les réseaux sociaux promettaient à leurs débuts un nouvel âge du débat démocratique, un lieu ouvert où chacun pourrait s’exprimer, se confronter aux idées des autres et tisser des liens, force est de constater qu’ils alimentent aujourd’hui des logiques opposées.');
INSERT INTO `wp_postmeta` VALUES (151,39,'_descriptif_desktop','field_olthem_thm_descriptif_desktop');
INSERT INTO `wp_postmeta` VALUES (152,39,'descriptif_mobile','La polarisation des opinions sur les réseaux sociaux, et la rarification progressive de la nuance dans les débats en ligne. Prendre le temps de ralentir, dans un environnement qui pousse à réagir vite, fort, parfois sans recul.');
