INSERT INTO `wp_postmeta` VALUES (166,40,'_titre','field_olthem_thm_titre');
INSERT INTO `wp_postmeta` VALUES (167,40,'descriptif_desktop','Souvent perçue comme un outil redoutable pour façonner les opinions et comportements, la propagande se faufile au coeur de nos sociétés. Elle est une « une tentative délibérée et systématique de façonner les perceptions, manipuler les capacités cognitives et contrôler le comportement de son récepteur afin de s’assurer une réponse qui serve l’intention souhaitée par le propagandiste » (Debras, 2024)');
