INSERT INTO `wp_postmeta` VALUES (220,41,'Builder_0_subsection_2_text','Salut, moi c’est Olga !\r\n\r\n<em>Dans cette société de l’immédiateté et de l’information, je dois avouer que je me sens parfois un peu perdue. Qui sont ces algorithmes qui dictent ma pensée ou qui me disent quelle musique écouter? Est-ce que je fais encore des choix sur Internet? Parfois, je me sens un peu enfermée dans une bulle. J’ai l’impression qu’on me balance que ce que j’aime. Au final, je dois la quitter ou pas ma bulle? </em>J’y suis bien, moi, dans ma bulle, avec mes potes, on se comprend...');
INSERT INTO `wp_postmeta` VALUES (221,41,'_Builder_0_subsection_2_text','field_69c4d54bbf536');
